  assert_error(
      "rule test { strings: $a = /[a\\/ condition: $a }",
      ERROR_SYNTAX_ERROR);

  // Test case for issue #996
  assert_error(
      "rule test {strings:$=/.{,}? /",
      ERROR_SYNTAX_ERROR);

  assert_true_rule_blob(
